int dfs(int x, const vector<vector<int>> &con, const vector<int> &a, vector<int> &dp) {
    long long may = 0;
    for (int y : con[x]) {
        may += dfs(y, con, a, dp);
    }
    return dp[x] = con[x].size() ? min((long long) a[x], may) : a[x];
}

long long solution(const vector<int> &v, const vector<int> &a) {
    const int n = v.size();
    vector<vector<int>> con(n);
    long long s = 0;
    for (int x : a) {
        s += x;
    }
    for (int i = 1; i < n; ++i) {
        con[v[i] - 1].push_back(i);
    }
    vector<int> dp(n);
    return s - dfs(0, con, a, dp);
}
int main() {
    cout << solution({0, 1, 1, 2, 2}, {7, 4, 2, 3, 4}) << endl;
    return 0;
}

