- Need to pick once and not to pick once. While doing so pass the info to lower child if in the current path already one skipped node exists or not. if exist then pick all subsequent nodes item other wise we have two options at lower nodes as well. Doing so memorise the sum of all lower node with skipped or not status.


```
class TreeNode{
    int val;
    int fruits;
    TreeNode* left, *right;
}

int solve(TreeNode* root, int alreadyPicked, vector<vector<int>>& dp){
    if(!root) return;
    if(dp[root->val][alreadyPicked]  != -1) return dp[root->val][alreadyPicked];
    int res = root->fruits + solve(root->left, 0, dp) + solve(root->right; 0, dp);                     // skipped
    if(!alreadyPicked) res = max(res, solve(root->left, 1, dp) + solve(root->right, 1, dp));   // taken
    return dp[root->val][alreadyPicked] = res;
}

int getMaxFruits(TreeNode* root){
      vector<vector<int>> dp(100001, vector<int>(2, -1));
      return solve(root, 0, dp);
}
